local sort_chain = Effect.GlobalEffect()
sort_chain:SetType(EFFECT_TYPE_FIELD + EFFECT_TYPE_CONTINUOUS)
sort_chain:SetCode(EVENT_STARTUP)
sort_chain:SetOperation(function()
  local attacker = Duel.GetFieldGroup(0, LOCATION_DECK, 0):GetFirst()
  Duel.MoveToField(attacker, 0, 0, LOCATION_MZONE, POS_FACEUP_ATTACK, true)

  local first_cost = Effect.CreateEffect(attacker)
  first_cost:SetType(EFFECT_TYPE_SINGLE)
  first_cost:SetCode(EFFECT_ATTACK_COST)
  first_cost:SetOperation(function() end)
  attacker:RegisterEffect(first_cost)

  local second_cost = Effect.CreateEffect(attacker)
  second_cost:SetType(EFFECT_TYPE_SINGLE)
  second_cost:SetCode(EFFECT_ATTACK_COST)
  second_cost:SetOperation(function()
    Duel.Win(0, 1)
  end)
  attacker:RegisterEffect(second_cost)
end)
Duel.RegisterEffect(sort_chain, 0)
